, outreach as (
    select
        ch.acco_id
        , ch.fbg_owner_id
        , min(ch.message_date) as first_outreach_date
        , count(*) as outreach_count
    from FBG_ANALYTICS.VIP.VIP_CONTACT_HISTORY ch
    join task_list t
        on ch.acco_id = t.acco_id
        and ch.fbg_owner_id = t.ownerid
    where ch.outbound = 1
      and ch.fbg_owner_id is not null
      and ch.message_date >= '2026-04-08'
    group by ch.acco_id, ch.fbg_owner_id
)

select
    t.vip_host
    , t.acco_id
    , case when o.acco_id is not null then 'Yes' else 'No' end as reached_out
    , o.first_outreach_date
    , o.outreach_count
from task_list t
left join outreach o
    on t.acco_id = o.acco_id
    and t.ownerid = o.fbg_owner_id
where REACHED_OUT = 'No'
order by t.vip_host, reached_out desc, t.acco_id
